import asyncio
import subprocess
import json
import os
from pathlib import Path
from typing import Dict, List, Optional, AsyncGenerator, Any
from rich.console import Console

console = Console()
from .config import ModelConfig

class LlamaCppClient:
    """Client for interacting with llama.cpp directly via subprocess"""

    def __init__(self, model_config: ModelConfig):
        self.config = model_config
        self.llama_cpp_path = "/home/commander/builds/llama-cpp-python/"
        self.models_dir = "/home/commander/Trainer/Models/MorphAlpha-v3-768/exports/gguf/"
        self.current_model_path = None
        self.interactive_mode = False
        self.history = None

    async def __aenter__(self):
        """Async context manager entry"""
        return self

    async def __aexit__(self, exc_type, exc_val, exc_tb):
        """Async context manager exit"""
        pass

    def update_config(self, model_config: ModelConfig):
        """Update the model configuration"""
        self.config = model_config

    async def is_available(self) -> bool:
        """Check if llama.cpp is available"""
        return os.path.exists(self.llama_cpp_path)

    def _find_gguf_model(self, model_name: str) -> Optional[str]:
        """Find GGUF model file by name or partial match"""
        models_dir = Path(self.models_dir)

        # Direct match with .gguf extension
        direct_path = models_dir / f"{model_name}.gguf"
        if direct_path.exists():
            return str(direct_path)

        # Check if model_name already includes .gguf
        if model_name.endswith('.gguf'):
            full_path = models_dir / model_name
            if full_path.exists():
                return str(full_path)

        # Fuzzy match - search for similar names
        for gguf_file in models_dir.glob("*.gguf"):
            # Match if model_name is substring (case-insensitive)
            if model_name.lower() in gguf_file.stem.lower():
                return str(gguf_file)

        return None

    async def is_model_available(self) -> bool:
        """Check if the configured model is available"""
        model_path = self._find_gguf_model(self.config.name)
        if model_path:
            self.current_model_path = model_path
            return True
        return False

    async def list_models(self) -> List[str]:
        """List all available GGUF models"""
        models_dir = Path(self.models_dir)
        if not models_dir.exists():
            return []

        gguf_files = list(models_dir.glob("*.gguf"))
        # Return just the filenames without .gguf extension for cleaner display
        return [f.stem for f in sorted(gguf_files)]

    async def stream_generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: Optional[str] = None,
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        options: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict]] = None
    ) -> AsyncGenerator[str, None]:
        """Generate response using llama.cpp with streaming output"""

        # Build the full prompt with system message
        full_prompt = ""
        if system_prompt:
            full_prompt = f"System: {system_prompt}\n\nUser: {prompt}\n\nAssistant:"
        else:
            full_prompt = prompt

        # Get model path
        if not self.current_model_path:
            model_path = self._find_gguf_model(self.config.name)
            if not model_path:
                raise Exception(f"Model not found: {self.config.name}")
            self.current_model_path = model_path

        # Apply overrides
        max_tokens = num_predict_override if num_predict_override else (self.config.max_tokens if hasattr(self.config, 'max_tokens') else 2048)
        temperature = temperature_override if temperature_override is not None else (self.config.temperature if hasattr(self.config, 'temperature') else 0.7)

        # Build command (CPU-only, minimal flags for compatibility)
        cmd = [
            self.llama_cpp_path,
            "-m", self.current_model_path,
            "-p", full_prompt,
            "-n", str(min(max_tokens, 512)),  # Limit to max 512 tokens to prevent runaway generation
            "--temp", str(temperature),
            "-t", "4",  # Use 4 CPU threads
            "--no-display-prompt"  # Don't echo the prompt back
        ]

        console.print(f"[dim cyan]▶ Starting llama.cpp generation...[/dim cyan]")

        if self.interactive_mode and hasattr(self, 'history') and hasattr(self.history, 'debug_timing') and self.history.debug_timing:
            console.print(f"[dim cyan]DEBUG: Running llama.cpp: {' '.join(cmd[:6])}...[/dim cyan]")
            console.print(f"[dim cyan]DEBUG: Full command: {' '.join(cmd)}[/dim cyan]")

        # Run llama.cpp as subprocess
        # Note: llama.cpp outputs response to stdout and debug info to stderr
        process = await asyncio.create_subprocess_exec(
            *cmd,
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.DEVNULL  # Suppress debug output
        )

        console.print(f"[dim green]✓ llama.cpp process started (PID: {process.pid})[/dim green]")
        console.print(f"[dim yellow]Loading model (this may take 30-60s with limited GPU)...[/dim yellow]")

        # Stream output with 120 second timeout for model loading
        try:
            first_token_timeout = 120  # Allow 120 seconds for model to load and produce first token

            # First, wait for ANY output with timeout
            console.print(f"[dim yellow]⏳ Waiting up to {first_token_timeout}s for model to load...[/dim yellow]")
            try:
                first_output = await asyncio.wait_for(process.stdout.read(100), timeout=first_token_timeout)

                if first_output:
                    console.print(f"[dim green]✓ Model loaded, streaming response...[/dim green]")
                    # Yield first chunk
                    yield first_output.decode('utf-8', errors='ignore')

                    # Then stream rest normally in larger chunks for better performance
                    while True:
                        chunk = await process.stdout.read(64)  # Read in 64-byte chunks
                        if not chunk:
                            break
                        yield chunk.decode('utf-8', errors='ignore')

            except asyncio.TimeoutError:
                console.print(f"\n[red]Error: Model loading timed out after {first_token_timeout}s[/red]")
                console.print(f"[yellow]Try using a smaller model or increase timeout[/yellow]")
                process.kill()

        except Exception as e:
            console.print(f"[red]Error during generation: {e}[/red]")
            raise
        finally:
            # Wait for process to complete
            try:
                await asyncio.wait_for(process.wait(), timeout=5)
            except asyncio.TimeoutError:
                process.kill()

    async def generate(
        self,
        prompt: str,
        system_prompt: Optional[str] = None,
        task_type: Optional[str] = None,
        num_predict_override: Optional[int] = None,
        temperature_override: Optional[float] = None,
        options_override: Optional[Dict[str, Any]] = None,
        options: Optional[Dict[str, Any]] = None,
        tools: Optional[List[Dict]] = None
    ) -> str:
        """Non-streaming generation (collect all output)"""
        result = ""
        async for chunk in self.stream_generate(
            prompt, system_prompt, task_type,
            num_predict_override, temperature_override, options_override,
            options, tools
        ):
            result += chunk
        return result.strip()

    async def unload_model(self) -> bool:
        """Unload model (no-op for llama.cpp subprocess mode)"""
        self.current_model_path = None
        return True
